class Solution:
    def smallestPalindrome(self, s, k):
        from itertools import permutations
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - 97] += 1
        half = []
        mid = ''
        for i in range(26):
            half.append(chr(97 + i) * (cnt[i] // 2))
            if cnt[i] % 2 == 1:
                mid = chr(97 + i)
        half_str = ''.join(half)
        seen = set()
        for p in permutations(half_str):
            h = ''.join(p)
            seen.add(h + mid + h[::-1])
        ordered = sorted(seen)
        if k > len(ordered):
            return ''
        return ordered[k - 1]

