class Solution:
    def smallestPalindrome(self, s, k):
        CAP = 10**6 + 5
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - 97] += 1
        half = [cnt[i] // 2 for i in range(26)]
        mid = ''
        for i in range(26):
            if cnt[i] % 2 == 1:
                mid = chr(97 + i)
        def multinomial(counts, total):
            # distinct permutations of the multiset, capped at CAP
            res = 1
            taken = 0
            for c in counts:
                for j in range(1, c + 1):
                    taken += 1
                    res = res * taken // j
                    if res > CAP:
                        return CAP
            return res
        m = sum(half)
        if k > multinomial(half, m):
            return ''
        result = []
        remaining = half[:]
        rem_total = m
        for _ in range(m):
            for i in range(26):
                if remaining[i] == 0:
                    continue
                remaining[i] -= 1
                ways = multinomial(remaining, rem_total - 1)
                if k <= ways:
                    result.append(chr(97 + i))
                    rem_total -= 1
                    break
                else:
                    k -= ways
                    remaining[i] += 1
            else:
                return ''
        h = ''.join(result)
        return h + mid + h[::-1]

