var smallestPalindrome = function(s, k) {
    const CAP = 1000005;
    const cnt = new Array(26).fill(0);
    for (const ch of s) cnt[ch.charCodeAt(0) - 97]++;
    const half = cnt.map(c => Math.floor(c / 2));
    let mid = '';
    for (let i = 0; i < 26; i++) if (cnt[i] % 2 === 1) mid = String.fromCharCode(97 + i);
    const multinomial = (counts) => {
        let res = 1, taken = 0;
        for (const c of counts) {
            for (let j = 1; j <= c; j++) {
                taken++;
                res = Math.floor(res * taken / j);
                if (res > CAP) return CAP;
            }
        }
        return res;
    };
    let m = half.reduce((a, b) => a + b, 0);
    if (k > multinomial(half)) return '';
    const remaining = half.slice();
    const result = [];
    for (let pos = 0; pos < m; pos++) {
        let placed = false;
        for (let i = 0; i < 26; i++) {
            if (remaining[i] === 0) continue;
            remaining[i]--;
            const ways = multinomial(remaining);
            if (k <= ways) {
                result.push(String.fromCharCode(97 + i));
                placed = true;
                break;
            } else {
                k -= ways;
                remaining[i]++;
            }
        }
        if (!placed) return '';
    }
    const h = result.join('');
    return h + mid + h.split('').reverse().join('');
};
